diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 73ba0f78e805..0d310fd63566 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3479,6 +3479,19 @@ Instruction *InstCombinerImpl::foldSelectOfBools(SelectInst &SI) {
     }
   }

+  // select (xor C, true), A, false where C and A are equivalent -> false
+  // This handles patterns like:
+  //   select (xor (trunc (lshr x, 31)), true), (icmp slt x, 0), false -> false
+  // where C (trunc (lshr x, 31)) and A (icmp slt x, 0) both test the sign bit of x.
+  Value *NotCond;
+  if (match(CondVal, m_Not(m_Value(NotCond))) && match(FalseVal, m_Zero())) {
+    // Check if NotCond and TrueVal are equivalent (each implies the other)
+    std::optional<bool> CondImpliesTrue = isImpliedCondition(NotCond, TrueVal, DL);
+    std::optional<bool> TrueImpliesCond = isImpliedCondition(TrueVal, NotCond, DL);
+    if (CondImpliesTrue && *CondImpliesTrue && TrueImpliesCond && *TrueImpliesCond)
+      return replaceInstUsesWith(SI, Zero);
+  }
+
   return nullptr;
 }

@@ -3908,6 +3921,40 @@ static Value *foldSelectBitTest(SelectInst &Sel, Value *CondVal, Value *TrueVal,
                                         CreateAnd, Builder))
     return X;

+  // Handle the case where the condition is a trunc of a sign bit extraction
+  // (lshr X, bw-1) and one of the select arms is icmp slt X, 0.
+  // In this case, the icmp is equivalent to the condition.
+  // select (trunc (lshr X, bw-1)), Y, (icmp slt X, 0) -> Y if Y is false
+  // select (trunc (lshr X, bw-1)), (icmp slt X, 0), Y -> Y if Y is false
+  if (isa<TruncInst>(CondVal)) {
+    Value *X;
+    // Check if V is lshr X, bw-1 (sign bit extraction)
+    if (match(V, m_LShr(m_Value(X), m_SpecificInt(
+                          APInt(V->getType()->getScalarSizeInBits(),
+                                V->getType()->getScalarSizeInBits() - 1))))) {
+      // Check if TrueVal is icmp slt X, 0
+      if (match(TrueVal, m_SpecificICmp(ICmpInst::ICMP_SLT, m_Specific(X),
+                                        m_Zero()))) {
+        // select Cond, (icmp slt X, 0), FalseVal
+        // Since Cond is equivalent to (icmp slt X, 0), this is:
+        // select Cond, Cond, FalseVal = Cond ? Cond : FalseVal
+        // If FalseVal is false, this is always false.
+        if (match(FalseVal, m_Zero()))
+          return FalseVal;
+      }
+      // Check if FalseVal is icmp slt X, 0
+      if (match(FalseVal, m_SpecificICmp(ICmpInst::ICMP_SLT, m_Specific(X),
+                                         m_Zero()))) {
+        // select Cond, TrueVal, (icmp slt X, 0)
+        // Since Cond is equivalent to (icmp slt X, 0), this is:
+        // select Cond, TrueVal, Cond = Cond ? TrueVal : Cond
+        // If TrueVal is false, this is always false.
+        if (match(TrueVal, m_Zero()))
+          return TrueVal;
+      }
+    }
+  }
+
   return nullptr;
 }

